const DB = {
  async get(k, d = null) {
    try {
      const r = localStorage.getItem(k);
      return r ? JSON.parse(r) : d;
    } catch {
      return d;
    }
  },
  async set(k, v) {
    try {
      localStorage.setItem(k, JSON.stringify(v));
    } catch {}
  }
};

