// ── PROFESSIONAL MALE FORMULAS ─────────────────────────────
// Mifflin-St Jeor (1990) — most validated for male athletes
// Qatar heat: +7% thermic effect of hot/humid environment
const QATAR_HEAT=1.07;
const ACTIVITY={"Low":1.40,"Medium":1.60,"High":1.80,"Very High":2.00};
const BMR_M=(w,h,a)=>Math.round(10*w+6.25*h-5*a+5);
const calcTDEE=(w,h,a,load,goal)=>{
  const bmr=BMR_M(w,h,a);
  let tdee=Math.round(bmr*(ACTIVITY[load]||1.7)*QATAR_HEAT);
  if(goal==="Lose body fat")tdee-=400;
  if(goal==="Gain muscle mass")tdee+=300;
  return{bmr,tdee};
};
const calcMacros=(tdee,weight,goal)=>{
  const p=Math.round(weight*(goal==="Gain muscle mass"?2.2:goal==="Lose body fat"?2.4:2.0));
  const f=Math.round(weight*(goal==="Lose body fat"?0.9:1.1));
  const c=Math.max(0,Math.round((tdee-p*4-f*9)/4));
  return{protein:p,fat:f,carb:c};
};
const leanMass=(w,bf)=>+(w*(1-bf/100)).toFixed(1);
const fatMass=(w,bf)=>+(w*bf/100).toFixed(1);
const bmiV=(w,h)=>h?+(w/((h/100)**2)).toFixed(1):0;
const ffmiV=(w,h,bf)=>h?+(leanMass(w,bf)/((h/100)**2)).toFixed(1):0;
const calcAge=dob=>{const b=new Date(dob),t=new Date();let a=t.getFullYear()-b.getFullYear();if(t.getMonth()<b.getMonth()||(t.getMonth()===b.getMonth()&&t.getDate()<b.getDate()))a--;return a;};
const getLast=p=>p.measurements?.length?p.measurements[p.measurements.length-1]:{weight:0,bodyFat:0,height:0,date:""};
const bfSt=bf=>bf<6?{l:"Dangerously Low",c:"#DC143C"}:bf<=10?{l:"Athletic",c:"#10B981"}:bf<=14?{l:"Fit",c:"#3B82F6"}:bf<=18?{l:"Acceptable",c:"#F59E0B"}:{l:"High",c:"#EF4444"};
const needsFU=p=>{const m=getLast(p);return m.bodyFat>18||m.bodyFat<5.5||(p.injuries&&p.injuries!=="None")||(p.measurements?.length>1&&Math.abs(m.weight-p.measurements[p.measurements.length-2].weight)>2);};
const defSupps=()=>SUPPS.map(s=>({key:s.key,enabled:false,selectedType:s.types[0],dose:s.dose,timing:s.timing}));
const AV=["#DC143C","#3B82F6","#10B981","#F59E0B","#8B5CF6","#EC4899"];
const getAV=id=>AV[(id||0)%AV.length];
const ini=name=>name.split(" ").slice(0,2).map(w=>w[0]).join("").toUpperCase();
const fmtT=(h,m)=>{const hh=((h%24)+24)%24;return`${hh%12||12}:${String(m).padStart(2,"0")} ${hh>=12?"PM":"AM"}`;};
const resizePhoto=dataUrl=>new Promise(r=>{const img=new Image();img.onload=()=>{const M=150,rt=Math.min(M/img.width,M/img.height);const c=document.createElement("canvas");c.width=Math.round(img.width*rt);c.height=Math.round(img.height*rt);c.getContext("2d").drawImage(img,0,0,c.width,c.height);r(c.toDataURL("image/jpeg",0.55));};img.src=dataUrl;});
const calcGoal=player=>{
  const m=getLast(player);if(!m.weight)return null;const res={};
  if(player.targetBodyFat){const tBF=+player.targetBodyFat;const wk=+(Math.abs(m.bodyFat-tBF)/0.4).toFixed(1);const start=player.startBodyFat||m.bodyFat+3;const prog=Math.max(0,Math.min(100,Math.round(100-Math.abs(m.bodyFat-tBF)/Math.max(0.1,Math.abs(start-tBF))*100)));res.bodyFat={current:m.bodyFat,target:tBF,weeksLeft:wk,progress:prog};}
  if(player.targetWeight){const tW=+player.targetWeight;const diff=+(tW-m.weight).toFixed(1);const wk=+(Math.abs(diff)/0.5).toFixed(1);const start=player.startWeight||m.weight;const prog=start===tW?100:Math.max(0,Math.min(100,Math.round(100-Math.abs(m.weight-tW)/Math.max(0.1,Math.abs(start-tW))*100)));res.weight={current:m.weight,target:tW,diff,weeksLeft:wk,progress:prog};}
  return Object.keys(res).length?res:null;
};

