const PCSS=`body{font-family:Arial,sans-serif;margin:0;padding:20px;color:#111;font-size:13px;}h1{font-size:22px;font-weight:700;margin-bottom:4px;}h2{font-size:15px;font-weight:700;margin:16px 0 8px;border-bottom:2px solid #DC143C;padding-bottom:4px;color:#DC143C;}.hd{display:flex;align-items:center;gap:14px;margin-bottom:16px;padding-bottom:12px;border-bottom:3px solid #DC143C;}.hd img{width:56px;height:56px;object-fit:contain;}.sub{color:#666;font-size:11px;margin-top:2px;}.g2{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:12px;}.g3{display:grid;grid-template-columns:1fr 1fr 1fr;gap:9px;margin-bottom:12px;}.bx{background:#f8f9fa;border:1px solid #dee2e6;border-radius:5px;padding:9px 12px;}.bl{font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;margin-bottom:2px;}.bv{font-size:17px;font-weight:700;}.bs{font-size:11px;color:#666;margin-top:1px;}table{width:100%;border-collapse:collapse;margin-bottom:12px;}th{background:#DC143C;color:#fff;padding:6px 9px;text-align:left;font-size:11px;text-transform:uppercase;}td{padding:5px 9px;border-bottom:1px solid #dee2e6;font-size:12px;}tr:nth-child(even){background:#f8f9fa;}.bdg{display:inline-block;padding:2px 7px;border-radius:10px;font-size:11px;font-weight:700;}.bg{background:#d1fae5;color:#065f46;}.br2{background:#fee2e2;color:#991b1b;}.bb{background:#dbeafe;color:#1e40af;}.by{background:#fef9c3;color:#854d0e;}.tip{background:#f0fdf4;border-left:3px solid #10B981;padding:7px 11px;margin:6px 0;font-size:12px;}.alr{background:#fef9c3;border-left:3px solid #F59E0B;padding:7px 11px;margin:6px 0;font-size:12px;}.cr{display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid #eee;font-size:12px;}.dg{color:#065f46;font-weight:700;}.dr{color:#991b1b;font-weight:700;}.ft{margin-top:20px;padding-top:10px;border-top:1px solid #ddd;font-size:10px;color:#999;text-align:center;}`;

// ── SHARE & EXPORT ────────────────────────────────────────────
const buildPrintPage=(html,title)=>`<!DOCTYPE html><html><head><title>${title}</title><meta charset="utf-8"><style>${PCSS}</style></head><body>${html}<div class="ft">Al Duhail SC Nutrition Management · ${new Date().toLocaleDateString()}</div></body></html>`;

const openPrint=(html,title)=>{
  // Try popup first (desktop)
  try{
    const w=window.open('','_blank','width=900,height=700');
    if(w){
      w.document.write(buildPrintPage(html,title));
      w.document.close();
      setTimeout(()=>w.print(),700);
      return;
    }
  }catch(e){}
  // Fallback: download as HTML file (mobile)
  try{
    const blob=new Blob([buildPrintPage(html,title)],{type:'text/html'});
    const url=URL.createObjectURL(blob);
    const a=document.createElement('a');
    a.href=url;a.download=title.replace(/[^a-z0-9]/gi,'_')+'.html';
    document.body.appendChild(a);a.click();
    setTimeout(()=>{URL.revokeObjectURL(url);document.body.removeChild(a);},1000);
  }catch(e){}
};

const shareT=async(txt,method)=>{
  const e=encodeURIComponent(txt);
  if(method==="copy"){
    try{await navigator.clipboard.writeText(txt);}
    catch{
      // fallback for clipboard
      const ta=document.createElement('textarea');ta.value=txt;
      document.body.appendChild(ta);ta.select();document.execCommand('copy');
      document.body.removeChild(ta);
    }
    return;
  }
  if(method==="native"&&navigator.share){
    try{await navigator.share({title:"Al Duhail SC Report",text:txt});return;}catch{}
  }
  if(method==="whatsapp"){window.open(`https://wa.me/?text=${e}`,'_blank');return;}
  if(method==="email"){window.open(`mailto:?subject=Al Duhail SC Nutrition Report&body=${e}`,'_blank');return;}
};

const canNativeShare=()=>!!navigator.share;

const logoTag=()=>`<img src="data:image/jpeg;base64,${LOGO}" style="width:56px;height:56px;object-fit:contain;" alt="logo"/>`;
const genPH=player=>{const m=getLast(player),age=calcAge(player.dob);const{bmr,tdee}=calcTDEE(m.weight,m.height,age,player.trainingLoad,player.nutritionGoal);const{protein,fat,carb}=calcMacros(tdee,m.weight,player.nutritionGoal);const bfs=bfSt(m.bodyFat);const gp=calcGoal(player);const hist=[...player.measurements].sort((a,b)=>new Date(b.date)-new Date(a.date)).slice(0,8).map(ms=>{const cls=ms.bodyFat<=10?'bg':ms.bodyFat<=14?'bb':ms.bodyFat<=18?'by':'br2';return`<tr><td>${ms.date}</td><td><b>${ms.weight}kg</b></td><td><span class="bdg ${cls}">${ms.bodyFat}%</span></td><td>${leanMass(ms.weight,ms.bodyFat)}kg</td><td>${fatMass(ms.weight,ms.bodyFat)}kg</td><td>${bmiV(ms.weight,ms.height)}</td><td>${ms.notes||'—'}</td></tr>`;}).join('');return`<div class="hd">${logoTag()}<div><h1>${player.name} ♂</h1><div class="sub">${player.position} · #${player.number} · ${player.nationality} · Age ${age}</div><div class="sub">Report: ${new Date().toLocaleDateString()} · Training: ${player.trainingTime||"16:00"}</div></div></div><h2>Body Composition</h2><div class="g3"><div class="bx"><div class="bl">Weight</div><div class="bv">${m.weight}kg</div></div><div class="bx"><div class="bl">Body Fat</div><div class="bv">${m.bodyFat}%</div><div class="bs">${bfs.l}</div></div><div class="bx"><div class="bl">Lean Mass</div><div class="bv">${leanMass(m.weight,m.bodyFat)}kg</div></div><div class="bx"><div class="bl">BMI</div><div class="bv">${bmiV(m.weight,m.height)}</div></div><div class="bx"><div class="bl">FFMI</div><div class="bv">${ffmiV(m.weight,m.height,m.bodyFat)}</div><div class="bs">Target 20–25</div></div><div class="bx"><div class="bl">Height</div><div class="bv">${m.height}cm</div></div></div><h2>Daily Nutrition — Mifflin-St Jeor Male + Qatar Heat ×1.07</h2><div class="g3"><div class="bx"><div class="bl">BMR</div><div class="bv">${bmr}kcal</div></div><div class="bx"><div class="bl">TDEE</div><div class="bv">${tdee}kcal</div></div><div class="bx"><div class="bl">Hydration</div><div class="bv">${["High","Very High"].includes(player.trainingLoad)?"4–5L":"3–4L"}</div></div><div class="bx"><div class="bl">Protein</div><div class="bv">${protein}g</div><div class="bs">${Math.round(protein*4/tdee*100)}% TDEE</div></div><div class="bx"><div class="bl">Carbs</div><div class="bv">${carb}g</div><div class="bs">${Math.round(carb*4/tdee*100)}% TDEE</div></div><div class="bx"><div class="bl">Fats</div><div class="bv">${fat}g</div><div class="bs">${Math.round(fat*9/tdee*100)}% TDEE</div></div></div>${gp?`<h2>Goals</h2><div class="g2">${gp.bodyFat?`<div class="bx"><div class="bl">BF Goal</div><div class="bv">${gp.bodyFat.current}%→${gp.bodyFat.target}%</div><div class="bs">${gp.bodyFat.progress}% complete · Est ${gp.bodyFat.weeksLeft}wks</div></div>`:""} ${gp.weight?`<div class="bx"><div class="bl">Weight Goal</div><div class="bv">${gp.weight.current}→${gp.weight.target}kg</div><div class="bs">${gp.weight.progress}% complete · Est ${gp.weight.weeksLeft}wks</div></div>`:""}</div>`:""}<h2>Measurement History</h2><table><thead><tr><th>Date</th><th>Weight</th><th>BF%</th><th>Lean</th><th>Fat</th><th>BMI</th><th>Notes</th></tr></thead><tbody>${hist}</tbody></table><h2>Medical</h2><div class="g2"><div class="bx"><div class="bl">Allergies</div><div class="bv" style="font-size:14px">${player.allergies||"None"}</div></div><div class="bx"><div class="bl">Injuries</div><div class="bv" style="font-size:14px">${player.injuries||"None"}</div></div></div>`;};
const genCH=(player,dA,dB,mA,mB)=>{if(!mA||!mB)return"";const days=Math.round((new Date(dB)-new Date(dA))/86400000);const wD=+(mB.weight-mA.weight).toFixed(1),bfD=+(mB.bodyFat-mA.bodyFat).toFixed(1),lD=+(leanMass(mB.weight,mB.bodyFat)-leanMass(mA.weight,mA.bodyFat)).toFixed(1);const ms=[{l:"Body Weight",a:mA.weight,b:mB.weight,u:"kg",inv:false},{l:"Body Fat %",a:mA.bodyFat,b:mB.bodyFat,u:"%",inv:true},{l:"Lean Mass",a:leanMass(mA.weight,mA.bodyFat),b:leanMass(mB.weight,mB.bodyFat),u:"kg",inv:false},{l:"Fat Mass",a:fatMass(mA.weight,mA.bodyFat),b:fatMass(mB.weight,mB.bodyFat),u:"kg",inv:true},{l:"BMI",a:bmiV(mA.weight,mA.height),b:bmiV(mB.weight,mB.height),u:"",inv:false},{l:"FFMI",a:ffmiV(mA.weight,mA.height,mA.bodyFat),b:ffmiV(mB.weight,mB.height,mB.bodyFat),u:"",inv:false}];const rows=ms.map(m=>{const d=+(m.b-m.a).toFixed(1);const imp=m.inv?d<0:d>0;return`<div class="cr"><div><b style="color:#1e40af">${m.a}${m.u}</b></div><div style="text-align:center;font-size:10px;color:#888;font-weight:600">${m.l}</div><div><b style="color:#065f46">${m.b}${m.u}</b> <span class="${d===0?"":(imp?"dg":"dr")}">${d===0?"—":d>0?`+${d}${m.u}`:`${d}${m.u}`}</span></div></div>`;}).join('');const verdict=bfD<-1&&lD>=0?"🏆 Excellent — fat lost, muscle preserved":bfD<-1?"✅ Good — body fat reduced":lD>1?"💪 Positive — lean mass gained":"📊 Within range — continue protocol";const rec=bfD>1?"400 kcal deficit + 30 min cardio":bfD<-2&&lD<-0.5?"Increase protein to 2.4g/kg + resistance training":"Continue protocol. Next assessment in 4–6 weeks.";return`<div class="hd">${logoTag()}<div><h1>Comparison: ${player.name} ♂</h1><div class="sub">${player.position} · Male · ${player.nationality}</div><div class="sub">${dA} → ${dB} (${days} days / ~${Math.round(days/7)} weeks)</div></div></div><h2>Before vs After</h2><div class="g2" style="margin-bottom:10px"><div class="bx" style="background:#dbeafe"><div class="bl" style="color:#1e40af">DATE A — BEFORE</div><div class="bv" style="color:#1e40af">${dA}</div></div><div class="bx" style="background:#d1fae5"><div class="bl" style="color:#065f46">DATE B — AFTER</div><div class="bv" style="color:#065f46">${dB}</div></div></div>${rows}<h2>Summary</h2><div class="g3"><div class="bx"><div class="bl">Duration</div><div class="bv">${days}d / ${Math.round(days/7)}wks</div></div><div class="bx"><div class="bl">Weight</div><div class="bv ${wD>0?"dr":"dg"}">${wD>0?"+":""}${wD}kg</div></div><div class="bx"><div class="bl">Body Fat</div><div class="bv ${bfD<0?"dg":"dr"}">${bfD>0?"+":""}${bfD}%</div></div><div class="bx"><div class="bl">Lean Mass</div><div class="bv ${lD>0?"dg":"dr"}">${lD>0?"+":""}${lD}kg</div></div><div class="bx"><div class="bl">Wk Weight</div><div class="bv">${+(wD/(days/7)).toFixed(2)}kg/wk</div><div class="bs">Safe ≤0.5</div></div><div class="bx"><div class="bl">Wk BF</div><div class="bv">${+(bfD/(days/7)).toFixed(2)}%/wk</div><div class="bs">Safe ≤0.5</div></div></div><h2>Assessment</h2><div class="tip">${verdict}</div><div class="alr"><b>Recommendation:</b> ${rec}</div>`;};
const genDH=players=>{const avgW=players.length?+(players.reduce((s,p)=>s+getLast(p).weight,0)/players.length).toFixed(1):0;const avgBf=players.length?+(players.reduce((s,p)=>s+getLast(p).bodyFat,0)/players.length).toFixed(1):0;const fu=players.filter(needsFU);const rows=players.map(p=>{const m=getLast(p);const cls=m.bodyFat<=10?"bg":m.bodyFat<=14?"bb":m.bodyFat<=18?"by":"br2";return`<tr><td><b>#${p.number}</b></td><td>${p.name}</td><td>${p.position}</td><td>${calcAge(p.dob)}</td><td>${m.weight}kg</td><td><span class="bdg ${cls}">${m.bodyFat}%</span></td><td>${leanMass(m.weight,m.bodyFat)}kg</td><td>${needsFU(p)?'<span class="bdg br2">⚠</span>':'<span class="bdg bg">✓</span>'}</td></tr>`;}).join('');return`<div class="hd">${logoTag()}<div><h1>Squad Nutrition Report</h1><div class="sub">Al Duhail SC · ${players.length} Players · All Male · ${new Date().toLocaleDateString()}</div></div></div><h2>Summary</h2><div class="g3"><div class="bx"><div class="bl">Players</div><div class="bv">${players.length}</div></div><div class="bx"><div class="bl">Avg Weight</div><div class="bv">${avgW}kg</div></div><div class="bx"><div class="bl">Avg BF</div><div class="bv">${avgBf}%</div><div class="bs">Target 8–14%</div></div></div><h2>Players</h2><table><thead><tr><th>#</th><th>Name</th><th>Position</th><th>Age</th><th>Weight</th><th>BF%</th><th>Lean</th><th>Status</th></tr></thead><tbody>${rows}</tbody></table>${fu.length?`<h2>⚠ Follow-up (${fu.length})</h2><div class="alr">${fu.map(p=>`<b>${p.name}</b>`).join(' · ')}</div>`:""}`;};

